@@ -10,6 +10,12 @@ use crate::{db, AppState};
 use axum::{extract::Path, extract::State, Json};
 use crate::models::User;
+
+pub async fn get_user(
+    State(state): State<AppState>,
+    Path(id): Path<i64>,
+) -> Json<User> {
+    let user = db::find_user(&state.pool, id).await.unwrap();
+    Json(user)
+}
